// SetManagerCompanies removes all previously related items of the
// user replacing them completely with the passed
// in related items, optionally inserting them as new records.
// Sets o.R.Manager's ManagerCompanies accordingly.
// Replaces o.R.ManagerCompanies with related.
// Sets related.R.Manager's ManagerCompanies accordingly.
func (o *User) SetManagerCompanies(ctx context.Context, exec boil.ContextExecutor, insert bool, related ...*Company) error {
	query := "update \"companies\" set \"manager_id\" = null where \"manager_id\" = $1"
	values := []any{o.ID}
	if boil.IsDebug(ctx) {
		writer := boil.DebugWriterFrom(ctx)
		fmt.Fprintln(writer, query)
		fmt.Fprintln(writer, values)
	}
	_, err := exec.ExecContext(ctx, query, values...)
	if err != nil {
		return errors.Wrap(err, "failed to remove relationships before set")
	}

	if o.R != nil {
		for _, rel := range o.R.ManagerCompanies {
			queries.SetScanner(&rel.ManagerID, nil)
			if rel.R == nil {
				continue
			}

			rel.R.Manager = nil
		}
		o.R.ManagerCompanies = nil
	}

	return o.AddManagerCompanies(ctx, exec, insert, related...)
}

// RemoveManagerCompanies relationships from objects passed in.
// Removes related items from R.ManagerCompanies (uses pointer comparison, removal does not keep order)
// Sets related.R.Manager.
func (o *User) RemoveManagerCompanies(ctx context.Context, exec boil.ContextExecutor, related ...*Company) error {
	if len(related) == 0 {
		return nil
	}

	var err error
	for _, rel := range related {
		queries.SetScanner(&rel.ManagerID, nil)
		if rel.R != nil {
			rel.R.Manager = nil
		}
		if _, err = rel.Update(ctx, exec, boil.Whitelist("manager_id")); err != nil {
			return err
		}
	}
	if o.R == nil {
		return nil
	}

	for _, rel := range related {
		for i, ri := range o.R.ManagerCompanies {
			if rel != ri {
				continue
			}

			ln := len(o.R.ManagerCompanies)
			if ln > 1 && i < ln-1 {
				o.R.ManagerCompanies[i] = o.R.ManagerCompanies[ln-1]
			}
			o.R.ManagerCompanies = o.R.ManagerCompanies[:ln-1]
			break
		}
	}

	return nil
}

